import{_ as i,r as o,o as a,c as n,b as e,d as t,e as r,a as c}from"./app-2a089349.js";const l={},u=e("h1",{id:"subscription-limit-one-subscription-per-email-address",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#subscription-limit-one-subscription-per-email-address","aria-hidden":"true"},"#"),t(" Subscription Limit: One Subscription Per Email Address")],-1),d=e("p",null,"In the context of typical website usage, if an account or subscription is already associated with an email address, it would not be possible for an individual to register on the site or subscribe to another subscription using the same email address. The UM Stripe Extension limits the subscription to one email per subscription and requires the use of a unique and valid email address for each subscription.",-1),h=e("p",null,"Limiting subscriptions to one email per user offers multiple advantages. It enhances user identity verification and accountability by tying each subscription to a unique email address. This measure also prevents abuse of promotional offers and free trials by discouraging the creation of duplicate accounts. Additionally, it contributes to a more secure authentication process, as users typically need access to their registered email accounts for security-related procedures. Furthermore, this policy ensures fair resource allocation and simplifies user account management and support. Ultimately, it improves the user experience by reducing confusion and login issues associated with managing multiple accounts under the same email address.",-1),p=e("h3",{id:"limit-customers-to-1-subscription",tabindex:"-1"},[e("a",{class:"header-anchor",href:"#limit-customers-to-1-subscription","aria-hidden":"true"},"#"),t(" Limit Customers to 1 Subscription")],-1),m=e("p",null,"To limit customers to 1 subscription per email address, do the following steps below:",-1),g={href:"https://dashboard.stripe.com/settings/checkout",target:"_blank",rel:"noopener noreferrer"},b=e("li",null,[t("In the Subscription section,enable the "),e("strong",null,"'Limit customers to 1 subscription'."),t(" For test mode, choose the "),e("strong",null,"'Test mode'"),t(" option. For the live site, select "),e("strong",null,"'Your website'"),t(" and input your site's login URL into the designated field. "),e("img",{src:"https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65c528d918ce7f6806c75531/file-QSOQrSDWAf.png",alt:""})],-1),f=e("li",null,[e("strong",null,"Save"),t(" your settings.")],-1),w=c('<p><strong>Situations and Resolutions</strong></p><p>In this section of the article, we delve into various Situations &amp; Resolutions, presenting potential scenarios you might encounter. Here, we offer comprehensive solutions and answers to address the challenges or questions that may arise.</p><p><strong>Situation 1:</strong> User <strong>&quot;John Doe&quot;</strong> registers to your site with the email address <a href="mailto:%C2%A0johndoe@um.net"> johndoe@um.net </a> and has successfully subscribed to your <strong>Basic subscription plan</strong>, so now he has an active subscription.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba4121a7493b27a932f7a9/file-tUoFiTdIeM.png" alt=""></p><p>While he was logged in, he decided that he wanted to upgrade his subscription. So he went to the subscription page and subscribed to the <strong>Premium Plan</strong> via the Subscribe URL.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba435a8e1d144482a9fc32/file-ZFD1V4KetI.png" alt=""></p><p>When he clicked the button with the Premium Plan subscribe URL, he was redirected to the <strong>Already Subscribed Page</strong> because he already had an existing subscription.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65ba43ffa7493b27a932f7ab/file-K6EMtpGQhy.png" alt=""></p><p><strong>Resolution 1:</strong> If you don&#39;t restrict 1 email to 1 subscription, this is how the Stripe extension handles the process and generates a Stripe customer and WP Account:</p><ul><li>When using the Register form with Stripe plans, a user will be created with a Stripe customer account with the email address field in the Email field. If there&#39;s no email field in the UM Register form, a generated email address will be supplied to the Stripe checkout. If the dedicated Stripe billing predefined field is added to the Register form, it will be used to create a Stripe customer account - this separates the Billing Email and WP Account email on registration.</li><li>When an existing WP account tries to checkout via the Stripe button, Payment Link, or Direct Checkout URL, a Stripe Customer account will be generated using their primary email address that&#39;s registered to their WP account( user_email from the wp_users table )</li><li>When a new user is added to the WP Admin &gt; Users, they will be created with a Stripe customer account and link both accounts together.</li></ul><p><strong>Situation 2:</strong> An unregistered user named &quot;<strong>Jane Doe&quot;</strong> attempted to subscribe to a plan via the subscription URL. However, upon reaching the checkout page, she entered the email address &#39;<a>johndoe@um.net</a>&#39;, which is already registered under the account of user John Doe. Consequently, Jane will be unable to complete the registration or subscription process using this email address, as it is already associated with an existing subscription. Instead, she will receive an error message indicating that the email address already has an active subscription.</p><p><img src="https://s3.amazonaws.com/helpscout.net/docs/assets/561c96629033600a7a36d662/images/65c52b1518ce7f6806c75539/file-mnBj1d7gOT.png" alt=""></p><p><strong>Resolution 2:</strong></p><ul><li>All existing and logged-in users will not get any new email address, when using the Stripe checkout shortcode for button or direct URL, it will generate a Stripe customer and different email on the Stripe dashboard if there&#39;s none, if there&#39;s already a Stripe customer account assigned to the WP user account, it will be used for the checkout process</li><li>Additional info, when you create a user in the WP Admin &gt; Users screen, it will also create a Stripe customer on account creation and the Stripe customer and WP Account will be linked together</li></ul>',14);function y(S,_){const s=o("ExternalLinkIcon");return a(),n("div",null,[u,d,h,p,m,e("ol",null,[e("li",null,[t("Go to Stripe Dashboard>Settings>Payments> "),e("a",g,[t("Checkout and Payment links"),r(s)])]),b,f]),w])}const k=i(l,[["render",y],["__file","1898-subscription-limit-one-subscription-per-email-address.html.vue"]]);export{k as default};
